// src/CinemaClubStats.js

import gameData from './gameData.json'; // Importando os dados dos filmes
import RatingChart from './RatingChart';
import GenreChart from './GenreChart';
import React from 'react';
import './CantinhoDoGueimerStats.css';
import Game from './Game';
import Gametr from './Gametr';
import { Link } from 'react-router-dom';

const CantinhoDoGueimerStats = () => {

    const cleanTitle = (str) => {
        return str.replace(/[^\w\s]/gi, ''); 
    };

    // Função para calcular o total de minutos assistidos
    const calculateTotalMinutes = () => {
        let totalMinutes = 0;
        for (const [, game] of Object.entries(gameData)) {
            totalMinutes += game.minutes;
        }
        return totalMinutes;
    };

    // Função para calcular a média de minutos por filme
    const calculateAverageMinutes = () => {
        const totalMinutes = calculateTotalMinutes();
        const totalGames = Object.keys(gameData).length;
        return totalMinutes / totalGames;
    };

    // Função para encontrar todas as pessoas únicas que assistiram aos filmes
    const findUniqueViewers = () => {
        const viewers = new Set();
        for (const [, game] of Object.entries(gameData)) {
            for (const viewer in game.reviews) {
                viewers.add(viewer);
            }
        }
        return viewers.size;
    };

    // Função para calcular o total de pessoas que assistiram aos filmes
    const calculateTotalViewers = () => {
        let totalViewers = 0;
        for (const [, game] of Object.entries(gameData)) {
            totalViewers += Object.keys(game.reviews).length;
        }
        return totalViewers;
    };

    // Função para calcular as estatísticas de notas
    const calculateRatingStats = () => {
        const ratings = {};


        for (const [, game] of Object.entries(gameData)) {
            for (const reviewer in game.reviews) {
                const rating = game.reviews[reviewer];
                if (ratings[rating*2]) {
                    ratings[rating*2]++;
                } else {
                    ratings[rating*2] = 1;
                }
            }
        }


        return ratings
    };

    // Função para calcular as estatísticas de gêneros
    const calculateGenreStats = () => {
        const genres = {};

        for (const [, game] of Object.entries(gameData)) {
            for (const genre of game.genres) {
                if (genres[genre]) {
                    genres[genre]++;
                } else {
                    genres[genre] = 1;
                }
            }
        }

        return genres;
    };

    const calculateTotalGames = () => {
        return Object.entries(gameData).length
    }

    const calculateAvaregeGames = () => {
        var averages = {}

        for (const [title, game] of Object.entries(gameData)) {
            var total_rating = 0
            var number_of_ratings = 0
            for (const reviewer in game.reviews) {
                total_rating += game.reviews[reviewer];
                number_of_ratings += 1;
            }
            var average = total_rating / number_of_ratings;
            averages[title] = average.toFixed(2);
        }
        return averages;
    }
    
    const calculateTopWatchers = () => {
        var watchers = {}
        var number_games = 0;

        var games = Object.entries(gameData).sort((a, b) => {

            var date1Parts = a[1].date.split("/");
            var date1Object = new Date(+date1Parts[2], date1Parts[1] - 1, +date1Parts[0]);

            var date2Parts = b[1].date.split("/");
            var date2Object = new Date(+date2Parts[2], date2Parts[1] - 1, +date2Parts[0]); 

            return date2Object - date1Object;
        });

        for (const [title, game] of games) {
            number_games+=1;
            let total_game_rating = 0;
            let total_game_reviews = 0;
            for (const [user, rating] of Object.entries(game.reviews)) {
                total_game_rating += rating;
                total_game_reviews += 1;
                

                if (user in watchers){
                    watchers[user]["total_games"] += 1
                    watchers[user]["total_ratings"] += rating
                    if(number_games === watchers[user]["total_games"]){
                        watchers[user]["streak"]+=1;
                    }
                    if(number_games <= 12){
                        watchers[user]["active"]+=1;
                    }
                    if(watchers[user]["total_games"] === 1){
                        watchers[user]["streak"] = -(number_games-1);
                    }
                }
                else {
                    watchers[user] = {
                        "total_games" : 1,
                        "total_ratings" : rating,
                        "choices" : 0,
                        "recommendations_ratings" : 0
                    }
                    if(number_games === 1){
                        watchers[user]["streak"] = 1;
                    }
                    else{
                        watchers[user]["streak"] = -(number_games-1);
                    }
                    if(number_games <= 12){
                        watchers[user]["active"]=1;
                    }
                    else{
                        watchers[user]["active"]=0;
                    }
                }
            }

            let average_game_rating = total_game_rating/total_game_reviews

            for(let i in game['chosen by']){
                if (game['chosen by'][i] in watchers){
                    watchers[game['chosen by'][i]]["choices"]+=1
                    watchers[game['chosen by'][i]]["recommendations_ratings"]+=average_game_rating
                }
                else{
                    watchers[game['chosen by'][i]] = {
                        "total_games" : 0,
                        "total_ratings" : 0,
                        "choices" : 1,
                        "streak" : 0,
                        "active" : 0,
                        "recommendations_ratings" : average_game_rating
                    }
                }
            }
            
            
        }
        return watchers
    }

    const calculateTopGames = () => {
        let games = Object.entries(gameData).map(([title,game]) => {
            var reviews = 0;
            var total_rating = 0;
            
            for (const [_, rating] of Object.entries(game.reviews)) {
                reviews += 1;
                total_rating += rating;
            }
            
            return {
                title,
                reviews : reviews,
                average : (total_rating/reviews).toFixed(2)
            }
        })

        games.sort((a, b) => b.average - a.average);

        return games;
    }

    function getTop10Viewers(data) {
        // Converte o objeto em um array de entradas [chave, valor]
        let entries = Object.entries(data);

        // Adiciona a média de avaliações para cada entrada
        entries = entries.map(([name, info]) => {
            var member_active = "No";
            if (info.active >= 4) {
                member_active = "Yes";
            }
            return {
                name,
                name: name,
                total_games: info.total_games,
                total_ratings: info.total_ratings,
                choices: info.choices,
                streak: info.streak,
                active: member_active,
                active_count: info.active,
                average_ratings: (info.total_ratings / info.total_games).toFixed(2),
                average_recommendations_ratings : (info.recommendations_ratings / info.choices).toFixed(2)
            };
        });
    
        // Ordena o array pelo total de filmes, do maior para o menor
        entries.sort((a, b) => {
            if (b.total_games === a.total_games) {
              return a.name.localeCompare(b.name); // Ordena alfabeticamente pelo nome
            }
            return b.total_games - a.total_games; // Ordena por total de filmes
          });
        return entries;
    }

    const watchers = calculateTopWatchers()
    const top = getTop10Viewers(watchers)
    let active_members = 0;

    top.forEach(viewer => {
        if (viewer.active === 'Yes') {
            active_members+= 1;
        }
    })

    const topGames = calculateTopGames()

    const top5 = topGames.slice(0, 5)
    const worst5 = topGames.reverse().slice(0,5)

    topGames.reverse()

    return (
        <div>
            <div className='title-site'>
                <h1>Stats of Clube de BilaCinema</h1>
            </div>
            <div className="button">
                <Link to="/"><button>Back</button></Link>
            </div>
            <div className="stats">
                <p>Total games: <b>{calculateTotalGames()}</b></p>
                <p>Members: <b>{findUniqueViewers()}</b></p>
            </div>

            <RatingChart data={calculateRatingStats()} />
            <GenreChart data={calculateGenreStats()} />
            <div className="top-bottom-games">
                <div className='stats'>
                    <p>Best Rated Games</p>
                </div>
                <div className='catalog'>
                    {top5.map((game) => (
                        <>
                            <div className='game' key={game.title}>
                                <Game
                                    key={game.title}
                                    title={game.title}
                                    year={gameData[game.title].year}
                                    link={gameData[game.title].link}
                                    date={gameData[game.title].date}
                                    chosenBy={gameData[game.title]["chosen by"]}
                                    genres={gameData[game.title].genres}
                                    reviews={gameData[game.title].reviews}
                                    comments={gameData[game.title].comments}
                                />
                                <div className='stats'>
                                    <p>{game.average}/5</p>
                                </div>
                                
                            </div>
                        </>
                    ))}
                </div>

                <div className='stats'>
                    <p>Worst Rated Games</p>
                </div>
                <div className='catalog'>
                    {worst5.map((game) => (
                        <>
                            <div className='game' key={game.title}>
                                <Game
                                    key={game.title}
                                    title={game.title}
                                    year={gameData[game.title].year}
                                    link={gameData[game.title].link}
                                    date={gameData[game.title].date}
                                    chosenBy={gameData[game.title]["chosen by"]}
                                    genres={gameData[game.title].genres}
                                    reviews={gameData[game.title].reviews}
                                    comments={gameData[game.title].comments}
                                />
                                <div className='stats'>
                                    <p>{game.average}/5</p>
                                </div>
                                
                            </div>
                        </>
                    ))}
                </div>

                <div className='stats'>
                <p>Top Gueimers</p>
                <table className='pretty-table'>
                    <thead>
                        <tr>
                            <th>#</th>
                            <th>User</th>
                            <th>Games Played</th>
                            <th>Average Rating</th>
                            <th>Recommendations</th>
                            <th>Average Recommendation Rating</th>
                        </tr>
                    </thead>
                    <tbody>
                        {top.map((viewer, index) => (
                            <tr key={viewer.name}>
                                    <td>{index + 1}</td>
                                    <td>
                                        <Link to={`/users/${viewer.name}`}>
                                            <div className='user'>
                                                <div className='top'>
                                                        <img src={`/cantinhodogueimer/pfp/${viewer.name}.png`} alt={`${viewer.name}`} />
                                                </div>
                                                <div className='bottom'>
                                                    {viewer.name}
                                                </div>
                                            </div>
                                        </Link>
                                    </td>
                                    <td>{viewer.total_games}</td>
                                    <td>{viewer.average_ratings}</td>
                                    <td>{viewer.choices}</td>
                                    {viewer.choices > 0 && <td>{viewer.average_recommendations_ratings}</td>}
                                    {viewer.choices == 0 && <td>-</td>}
                            </tr>
                        ))}
                    </tbody>
                </table>

                <table className='pretty-table'>
                    <thead>
                        <tr>
                            <th>#</th>
                            <th>Poster</th>
                            <th>Title</th>
                            <th>Year</th>
                            <th>Recommendation</th>
                            <th>Players</th>
                            <th>Average Rating</th>
                        </tr>
                    </thead>
                    <tbody>
                        {topGames.map((game,index) => (
                            <Gametr
                            key={game.title}
                            index={index}
                            title={game.title}
                            year={gameData[game.title].year}
                            link={gameData[game.title].link}
                            date={gameData[game.title].date}
                            chosenBy={gameData[game.title]["chosen by"]}
                            genres={gameData[game.title].genres}
                            reviews={gameData[game.title].reviews}
                            nreviews={game.reviews}
                            average={game.average}
                            comments={gameData[game.title].comments}
                        />
                        ))}
                    </tbody>
                </table>
            </div>
            </div>
        </div>

        
    );
}

export default CantinhoDoGueimerStats;
