import { useState, useEffect } from "react";
import gameData from "./gameData.json";
import "./ClipsPage.css"

const ClipsPage = () => {
  const [clips, setClips] = useState([]);
  const [selectedClipIndex, setSelectedClipIndex] = useState(null);
  const [selectedGame, setSelectedGame] = useState("todos");
  const [selectedClipper, setSelectedClipper] = useState("todos");

  useEffect(() => {
    const allClips = [];

    for (const gameName in gameData) {
      const objGame = gameData[gameName];
      if ("clips" in objGame) {
        const clipsGames = objGame["clips"];
        for (const clip of clipsGames) {
          allClips.push({
            ...clip,
            game: gameName,
          });
        }
      }
    }

    // Ordenar por data (mais recente primeiro)
    allClips.sort((a, b) => new Date(b.data) - new Date(a.data));
    
    setClips(allClips);
  }, []);

  const filteredClips = clips.filter((clip) => {
    const gameOk = selectedGame === "todos" || clip.game === selectedGame;
    const clipperOk = selectedClipper === "todos" || clip.cliped_by === selectedClipper;
    return gameOk && clipperOk;
  });

  const uniqueGames = [...new Set(clips.map((clip) => clip.game))];
  const uniqueClippers = [...new Set(clips.map((clip) => clip.cliped_by))];

  return (
    <div className="p-6 space-y-6">
      <h1 className="text-3xl font-bold">🎮 Clips do Gueimer</h1>

      {/* Filtros */}
      <div className="flex flex-wrap gap-4">
        <div>
          <label className="block font-semibold">Filtrar por jogo: </label>
          <select
            className="p-2 border rounded"
            value={selectedGame}
            onChange={(e) => setSelectedGame(e.target.value)}
          >
            <option value="todos">Todos</option>
            {uniqueGames.map((game) => (
              <option key={game} value={game}>
                {game}
              </option>
            ))}
          </select>
        </div>

        <div>
          <label className="block font-semibold">Filtrar por quem clipou: </label>
          <select
            className="p-2 border rounded"
            value={selectedClipper}
            onChange={(e) => setSelectedClipper(e.target.value)}
          >
            <option value="todos">Todos</option>
            {uniqueClippers.map((clipper) => (
              <option key={clipper} value={clipper}>
                {clipper}
              </option>
            ))}
          </select>
        </div>
      </div>

      {/* Lista de títulos + vídeo embutido */}
      <ul className="space-y-4 border-t pt-4">
        {filteredClips.map((clip, idx) => (
          <li key={idx} className="clip-item">
          <div className="clip-header" onClick={() => setSelectedClipIndex(idx === selectedClipIndex ? null : idx)}>
            <span className="clip-title">{clip.title}</span>
            <span className="clip-meta">{clip.game} · {clip.cliped_by}</span>
          </div>
        
          {selectedClipIndex === idx && (
            <div className="clip-details">
              <iframe
                className="clip-video"
                width="640"
                height="360"
                src={clip.link}
                allow="autoplay"
                allowFullScreen
              ></iframe>
        
              <div className="clip-info">
                <img
                  src={`/cantinhodogueimer/pfp/${clip.cliped_by}.png`}
                  alt={clip.cliped_by}
                  className="clip-avatar"
                />
                <span className="clip-name">{clip.cliped_by}</span>
              </div>
        
              <p className="clip-extra">🎮 Jogo: {clip.game}</p>
              <p className="clip-extra">📅 Data: {clip.data}</p>
            </div>
          )}
        </li>
        ))}
      </ul>
    </div>
  );
};

export default ClipsPage;
